{"action":"created","comment":{"url":"https://api.github.com/repos/JuliaLang/julia/pulls/comments/809702686","pull_request_review_id":886865924,"id":809702686,"node_id":"PRRC_kwDOABkWpM4wQxUe","diff_hunk":"@@ -49,15 +49,22 @@ jl_combined_results g_combined_results; // Will live forever.
 // === stack stuff ===

 jl_raw_backtrace_t get_raw_backtrace() JL_NOTSAFEPOINT {
-    // A single large buffer to record backtraces onto
